@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_loading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-error">
            Something went wrong. Please try again.
        </div>
    }
    else if (_searched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" />
                    <div class="product-card-body">
                        <h4>@product.Name</h4>
                        <span class="product-card-price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _loading;
    private bool _searched;
    private Exception? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any in-flight search immediately so it doesn't overwrite
        // results from the new query.
        CancelPendingSearch();

        _debounceTimer?.Dispose();
        var captured = _query;
        _debounceTimer = new Timer(_ => InvokeAsync(() => ExecuteSearchAsync(captured)),
                                   state: null,
                                   dueTime: 300,
                                   period: Timeout.Infinite);
    }

    private async Task ExecuteSearchAsync(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
        {
            _results = new();
            _searched = false;
            _error = null;
            _loading = false;
            StateHasChanged();
            return;
        }

        _loading = true;
        _error = null;
        StateHasChanged();

        var cts = new CancellationTokenSource();
        _searchCts = cts;

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            // Only apply results if this search was not superseded.
            if (cts.Token.IsCancellationRequested)
                return;

            _results = results;
            _searched = true;
            _error = null;
        }
        catch (OperationCanceledException)
        {
            // Search was abandoned because the user typed again — do nothing.
            return;
        }
        catch (Exception ex)
        {
            if (cts.Token.IsCancellationRequested)
                return;

            _results = new();
            _error = ex;
        }
        finally
        {
            // Only clear loading if this is still the active search.
            if (_searchCts == cts)
                _loading = false;

            cts.Dispose();
        }

        StateHasChanged();
    }

    private void CancelPendingSearch()
    {
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = null;
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        CancelPendingSearch();
    }
}

